// Some portions generated by Claude Code
package org.eclipse.rdf4j.common.iteration;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;

import java.util.Arrays;
import java.util.Iterator;
import java.util.List;

import org.eclipse.rdf4j.model.Value;
import org.junit.jupiter.api.Test;

/**
 * Tests the advisory defaults of {@link CloseableIteration#seek(Value, boolean, Value, boolean)} and
 * {@link CloseableIteration#supportsSeek()}.
 */
public class CloseableIterationSeekDefaultTest {

	private static final class ListIteration implements CloseableIteration<String> {

		private final Iterator<String> delegate;

		private ListIteration(List<String> elements) {
			this.delegate = elements.iterator();
		}

		@Override
		public boolean hasNext() {
			return delegate.hasNext();
		}

		@Override
		public String next() {
			return delegate.next();
		}

		@Override
		public void close() {
		}
	}

	@Test
	public void defaultSupportsSeekIsFalse() {
		try (CloseableIteration<String> iteration = new ListIteration(Arrays.asList("a", "b"))) {
			assertFalse(iteration.supportsSeek());
		}
	}

	@Test
	public void defaultSeekIsANoOp() {
		try (CloseableIteration<String> iteration = new ListIteration(Arrays.asList("a", "b", "c"))) {
			iteration.seek(null, true, null, true);
			assertEquals("a", iteration.next());
			iteration.seek(null, false, null, false);
			assertEquals("b", iteration.next());
			assertEquals("c", iteration.next());
			assertFalse(iteration.hasNext());
		}
	}
}
